{
 "level": "A1–B1",
 "intro": "This section brings together the main question patterns in English: from basic yes / no questions to negative questions and question tags.",
 "rules": [
 {
 "label": "Yes / No",
 "color": "emerald",
 "text": "<strong>General questions</strong> with a yes or no answer:",
 "example": "Do you like coffee?"
 },
 {
 "label": "Wh",
 "color": "blue",
 "text": "<strong>Wh-questions</strong> with question words:",
 "example": "What do you want?"
 },
 {
 "label": "Tags & Negatives",
 "color": "rose",
 "text": "<strong>Question tags</strong> and <strong>negative questions</strong> add confirmation, surprise, or expectation:",
 "example": "You know him, don't you? / Don't you know him?"
 }
 ]
}
